```java
import java.util.Scanner;

class Triangle {
    private double a, b, c;

    public void setSides(double a, double b, double c) {
        this.a = a;
        this.b = b;
        this.c = c;
    }

    public String getType() {
        // Kiểm tra tam giác hợp lệ
        if (a + b <= c || a + c <= b || b + c <= a) {
            return "Khong phai tam giac";
        }

        // Xác định loại tam giác
        if (a == b && b == c) {
            return "Tam giac deu";
        } else if (a == b || b == c || a == c) {
            return "Tam giac can";
        } else if (isRightTriangle()) {
            return "Tam giac vuong";
        } else {
            return "Tam giac thuong";
        }
    }

    private boolean isRightTriangle() {
        double[] sides = {a, b, c};
        // Sắp xếp để tìm cạnh lớn nhất
        for (int i = 0; i < 2; i++) {
            for (int j = i + 1; j < 3; j++) {
                if (sides[i] > sides[j]) {
                    double temp = sides[i];
                    sides[i] = sides[j];
                    sides[j] = temp;
                }
            }
        }
        // Kiểm tra định lý Pythagoras
        return Math.abs(sides[0]*sides[0] + sides[1]*sides[1] - sides[2]*sides[2]) < 0.001;
    }
}

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Nhap canh a: ");
        double a = scanner.nextDouble();
        System.out.print("Nhap canh b: ");
        double b = scanner.nextDouble();
        System.out.print("Nhap canh c: ");
        double c = scanner.nextDouble();

        Triangle t = new Triangle();
        t.setSides(a, b, c);

        System.out.println("Loai tam giac: " + t.getType());
        scanner.close();
    }
}
```

